<section class="page-intro container checkout-intro"><span class="eyebrow">Secure order request</span><h1>Checkout</h1><p>Your products, eligibility and availability are validated before the order is submitted.</p></section>
<section class="checkout-layout container"><form method="post" class="checkout-form" data-checkout-form><?= csrf_field() ?><input type="hidden" name="cart_json" data-cart-json>
  <div class="checkout-card"><span class="step-label">1 · Fulfillment</span><h2>How would you like your order?</h2><div class="choice-grid"><?php if(setting('pickup_enabled')): ?><label class="choice-card"><input type="radio" name="fulfillment" value="pickup" checked><i data-lucide="store"></i><span><strong>Pickup</strong><small><?= e(setting('pickup_address') ?: 'Location shared after confirmation') ?></small></span></label><?php endif; ?><?php if(setting('delivery_enabled')): ?><label class="choice-card"><input type="radio" name="fulfillment" value="delivery" <?= !setting('pickup_enabled')?'checked':'' ?>><i data-lucide="truck"></i><span><strong>Delivery</strong><small>Minimum <?= money((int)setting('delivery_minimum_cents')) ?></small></span></label><?php endif; ?></div></div>
  <div class="checkout-card"><span class="step-label">2 · Contact</span><h2>Who is placing the order?</h2><div class="form-grid"><label>Full name<input name="customer_name" value="<?= e($user['name']??'') ?>" autocomplete="name" required></label><label>Email<input type="email" name="customer_email" value="<?= e($user['email']??'') ?>" autocomplete="email" required></label><label class="full">Phone<input type="tel" name="customer_phone" value="<?= e($user['phone']??'') ?>" autocomplete="tel" required></label></div></div>
  <div class="checkout-card" data-delivery-fields><span class="step-label">3 · Delivery address</span><h2>Where should it go?</h2><div class="form-grid"><label class="full">Street address<input name="address1" autocomplete="address-line1"></label><label class="full">Apartment or suite<input name="address2" autocomplete="address-line2"></label><label>City<input name="city" autocomplete="address-level2"></label><label>State<input name="state" value="NY" readonly></label><label>ZIP code<input name="postal_code" inputmode="numeric" autocomplete="postal-code"></label><label>Requested time<input type="datetime-local" name="requested_time"></label><?php if($user): ?><label class="check-row full"><input type="checkbox" name="save_address" value="1"><span>Save this address to my account</span></label><?php endif; ?></div><p class="form-hint"><i data-lucide="map-pin"></i>Serving <?= e(setting('service_areas')) ?></p></div>
  <div class="checkout-card"><span class="step-label">4 · Payment and confirmation</span><h2>Choose payment</h2><div class="choice-stack"><?php if(setting('pay_at_pickup_enabled')): ?><label class="choice-card payment-pickup"><input type="radio" name="payment_method" value="pay_at_pickup" checked><i data-lucide="wallet-cards"></i><span><strong>Pay at pickup</strong><small>Available only for approved pickup orders.</small></span></label><?php endif; ?><?php if(setting('manual_prepaid_enabled')): ?><label class="choice-card"><input type="radio" name="payment_method" value="manual_prepaid" <?= !setting('pay_at_pickup_enabled')?'checked':'' ?>><i data-lucide="landmark"></i><span><strong>Prepaid arrangement</strong><small>The owner sends approved payment instructions after confirming availability.</small></span></label><?php endif; ?><?php if(setting('online_payment_enabled')): ?><label class="choice-card"><input type="radio" name="payment_method" value="online"><i data-lucide="credit-card"></i><span><strong>Online payment</strong><small>Use the configured approved payment provider.</small></span></label><?php endif; ?></div><label class="full">Order notes<textarea name="customer_notes" rows="3" placeholder="Delivery details or product preferences"></textarea></label><label class="check-row"><input type="checkbox" name="age_attestation" value="1" required><span>I confirm that I am 21 or older and will present valid identification when the order is fulfilled.</span></label></div>
  <button class="button button-primary button-wide button-large" type="submit">Submit order for confirmation<i data-lucide="check-circle-2"></i></button>
</form><aside class="checkout-summary"><div class="summary-sticky"><span class="eyebrow">Order summary</span><div data-checkout-items></div><div class="cart-total"><span>Subtotal</span><strong data-checkout-total>$0.00</strong></div><p>Final availability, discounts, fees and required payment are confirmed by the owner.</p><a href="<?= url('menu') ?>">Continue shopping</a></div></aside></section>
